import React, { useState, useEffect } from 'react';
import { Routes, Route, Link, useNavigate, useLocation } from 'react-router-dom';
import Navbar from '../components/shared/Navbar';
import { adminAPI } from '../utils/api';
import { format } from 'date-fns';
import toast from 'react-hot-toast';

function DashboardHome() {
  const [data, setData] = useState(null);
  useEffect(() => { adminAPI.getDashboard().then(r => setData(r.data.data)).catch(() => {}); }, []);
  if (!data) return <div className="spinner" />;

  return (
    <div className="animate-fade">
      <h2 style={{ fontSize: 22, fontWeight: 800, marginBottom: 20 }}>Dashboard Overview</h2>
      <div className="grid-4" style={{ marginBottom: 28 }}>
        {[
          { label: 'Total Users', value: data.totalUsers, icon: '👥', color: 'accent' },
          { label: 'Active Providers', value: data.totalProviders, icon: '🛠️', color: 'success' },
          { label: 'Pending Approval', value: data.pendingProviders, icon: '⏳', color: 'warning' },
          { label: 'Total Revenue', value: `₹${(data.totalRevenue || 0).toLocaleString()}`, icon: '💰', color: 'success' },
        ].map(s => (
          <div key={s.label} className="stat-card">
            <div className="stat-icon" style={{ background: `var(--${s.color}-dim)` }}>{s.icon}</div>
            <div><div className="stat-value">{s.value}</div><div className="stat-label">{s.label}</div></div>
          </div>
        ))}
      </div>

      <div className="card">
        <h3 style={{ fontWeight: 700, marginBottom: 16, fontSize: 15 }}>Recent Bookings</h3>
        {data.recentBookings?.map(b => (
          <div key={b._id} style={{ display: 'flex', justifyContent: 'space-between', padding: '10px 0', borderBottom: '1px solid var(--border)', fontSize: 13 }}>
            <div>
              <span style={{ fontWeight: 600 }}>{b.user?.name}</span>
              <span style={{ color: 'var(--text-muted)', marginLeft: 8 }}>→ {b.provider?.user?.name}</span>
            </div>
            <span className={`badge badge-${{ pending: 'warning', completed: 'success', cancelled: 'danger', accepted: 'accent' }[b.status] || 'muted'}`}>
              {b.status}
            </span>
          </div>
        ))}
      </div>
    </div>
  );
}

function ProviderApprovals() {
  const [providers, setProviders] = useState([]);
  const [loading, setLoading] = useState(true);

  const fetch = () => adminAPI.getPendingProviders().then(r => setProviders(r.data.data)).finally(() => setLoading(false));
  useEffect(() => { fetch(); }, []);

  const verify = async (id, status) => {
    const note = status === 'rejected' ? prompt('Rejection reason (optional):') : '';
    try {
      await adminAPI.verifyProvider(id, { status, note });
      toast.success(`Provider ${status}`);
      fetch();
    } catch { toast.error('Action failed'); }
  };

  return (
    <div className="animate-fade">
      <h2 style={{ fontSize: 22, fontWeight: 800, marginBottom: 20 }}>Provider Approvals</h2>
      {loading ? <div className="spinner" /> : providers.length === 0 ? (
        <div className="empty-state card"><div className="empty-state-icon">✅</div><h3>No pending approvals</h3></div>
      ) : providers.map(p => (
        <div key={p._id} className="card" style={{ marginBottom: 12 }}>
          <div style={{ display: 'flex', gap: 12, flexWrap: 'wrap', alignItems: 'flex-start' }}>
            <div style={{ flex: 1 }}>
              <div style={{ fontWeight: 700, fontSize: 16 }}>{p.user?.name}</div>
              <div style={{ fontSize: 13, color: 'var(--text-secondary)', marginTop: 2 }}>{p.user?.email} • {p.user?.phone}</div>
              <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap', marginTop: 8 }}>
                <span className="badge badge-accent">{p.serviceCategory}</span>
                {p.skills?.slice(0, 3).map(s => <span key={s} className="badge badge-muted">{s}</span>)}
              </div>
              <div style={{ fontSize: 13, color: 'var(--text-muted)', marginTop: 8 }}>
                📍 {p.location?.address} • 💼 {p.experience}y exp • ₹{p.priceRange?.min}–{p.priceRange?.max}
              </div>
              <div style={{ fontSize: 11, color: 'var(--text-muted)', marginTop: 4 }}>
                Registered: {format(new Date(p.user?.createdAt || Date.now()), 'd MMM yyyy')}
              </div>
            </div>
            <div style={{ display: 'flex', gap: 8 }}>
              <button className="btn btn-success btn-sm" onClick={() => verify(p._id, 'approved')}>✅ Approve</button>
              <button className="btn btn-danger btn-sm" onClick={() => verify(p._id, 'rejected')}>❌ Reject</button>
            </div>
          </div>
        </div>
      ))}
    </div>
  );
}

function UserManagement() {
  const [users, setUsers] = useState([]);
  const [search, setSearch] = useState('');
  const [role, setRole] = useState('');
  const [loading, setLoading] = useState(true);

  const fetch = () => adminAPI.getUsers({ search, role }).then(r => setUsers(r.data.data)).finally(() => setLoading(false));
  useEffect(() => { fetch(); }, [search, role]);

  const toggle = async (id) => {
    try {
      await adminAPI.toggleUser(id);
      toast.success('User status updated');
      fetch();
    } catch { toast.error('Failed'); }
  };

  return (
    <div className="animate-fade">
      <h2 style={{ fontSize: 22, fontWeight: 800, marginBottom: 20 }}>User Management</h2>
      <div style={{ display: 'flex', gap: 10, marginBottom: 16, flexWrap: 'wrap' }}>
        <input className="form-input" placeholder="Search name or email..." style={{ maxWidth: 300 }} value={search} onChange={e => setSearch(e.target.value)} />
        <select className="form-select" style={{ width: 140 }} value={role} onChange={e => setRole(e.target.value)}>
          <option value="">All Roles</option>
          <option value="user">Users</option>
          <option value="provider">Providers</option>
        </select>
      </div>
      {loading ? <div className="spinner" /> : (
        <div style={{ overflowX: 'auto' }}>
          <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 13 }}>
            <thead>
              <tr style={{ borderBottom: '1px solid var(--border)' }}>
                {['Name', 'Email', 'Phone', 'Role', 'Status', 'Joined', 'Action'].map(h => (
                  <th key={h} style={{ padding: '10px 12px', textAlign: 'left', color: 'var(--text-muted)', fontWeight: 500, textTransform: 'uppercase', fontSize: 11, letterSpacing: 1 }}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {users.map(u => (
                <tr key={u._id} style={{ borderBottom: '1px solid var(--border)' }}>
                  <td style={{ padding: '12px', fontWeight: 600 }}>{u.name}</td>
                  <td style={{ padding: '12px', color: 'var(--text-secondary)' }}>{u.email}</td>
                  <td style={{ padding: '12px', color: 'var(--text-secondary)' }}>{u.phone}</td>
                  <td style={{ padding: '12px' }}><span className={`badge badge-${u.role === 'admin' ? 'danger' : u.role === 'provider' ? 'success' : 'accent'}`}>{u.role}</span></td>
                  <td style={{ padding: '12px' }}><span className={`badge badge-${u.isActive ? 'success' : 'danger'}`}>{u.isActive ? 'Active' : 'Disabled'}</span></td>
                  <td style={{ padding: '12px', color: 'var(--text-muted)' }}>{format(new Date(u.createdAt), 'd MMM yy')}</td>
                  <td style={{ padding: '12px' }}>
                    <button className={`btn btn-sm ${u.isActive ? 'btn-danger' : 'btn-success'}`} onClick={() => toggle(u._id)}>
                      {u.isActive ? 'Disable' : 'Enable'}
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

function AllBookings() {
  const [bookings, setBookings] = useState([]);
  const [status, setStatus] = useState('');
  useEffect(() => { adminAPI.getBookings({ status }).then(r => setBookings(r.data.data)).catch(() => {}); }, [status]);

  return (
    <div className="animate-fade">
      <h2 style={{ fontSize: 22, fontWeight: 800, marginBottom: 20 }}>All Bookings</h2>
      <select className="form-select" style={{ width: 180, marginBottom: 16 }} value={status} onChange={e => setStatus(e.target.value)}>
        <option value="">All Statuses</option>
        {['pending', 'accepted', 'in_progress', 'completed', 'cancelled', 'rejected'].map(s => <option key={s} value={s}>{s}</option>)}
      </select>
      <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
        {bookings.map(b => (
          <div key={b._id} className="card" style={{ fontSize: 13 }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', flexWrap: 'wrap', gap: 8 }}>
              <div>
                <span style={{ fontWeight: 600 }}>{b.user?.name}</span>
                <span style={{ color: 'var(--text-muted)', margin: '0 6px' }}>→</span>
                <span style={{ fontWeight: 600 }}>{b.provider?.user?.name}</span>
                <span style={{ color: 'var(--text-secondary)', marginLeft: 8 }}>({b.skillRequired})</span>
              </div>
              <div style={{ display: 'flex', gap: 8, alignItems: 'center' }}>
                <span style={{ color: 'var(--text-muted)' }}>{format(new Date(b.scheduledDate), 'd MMM yyyy')}</span>
                <span className={`badge badge-${{ pending: 'warning', completed: 'success', cancelled: 'danger', accepted: 'accent', in_progress: 'accent', rejected: 'danger' }[b.status]}`}>{b.status}</span>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

const NAV_ITEMS = [
  { path: '', label: '📊 Overview' },
  { path: 'approvals', label: '✅ Provider Approvals' },
  { path: 'users', label: '👥 Users' },
  { path: 'bookings', label: '📋 Bookings' },
];

export default function AdminDashboard() {
  const location = useLocation();
  const navigate = useNavigate();

  return (
    <div style={{ minHeight: '100vh' }}>
      <Navbar />
      <div style={{ display: 'flex', minHeight: 'calc(100vh - 64px)' }}>
        {/* Sidebar */}
        <div style={{ width: 220, background: 'var(--bg-secondary)', borderRight: '1px solid var(--border)', padding: '24px 12px', flexShrink: 0 }}>
          <div style={{ fontSize: 11, color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: 1, marginBottom: 12, paddingLeft: 12 }}>Admin Panel</div>
          {NAV_ITEMS.map(item => {
            const fullPath = `/admin${item.path ? '/' + item.path : ''}`;
            const isActive = location.pathname === fullPath || (item.path === '' && location.pathname === '/admin');
            return (
              <Link key={item.path} to={fullPath}
                style={{
                  display: 'block', padding: '10px 12px', borderRadius: 'var(--radius)',
                  color: isActive ? 'var(--text-primary)' : 'var(--text-secondary)',
                  background: isActive ? 'var(--bg-elevated)' : 'transparent',
                  fontWeight: isActive ? 600 : 400, fontSize: 14, marginBottom: 2,
                  transition: 'all 0.15s',
                }}>
                {item.label}
              </Link>
            );
          })}
        </div>

        {/* Content */}
        <div style={{ flex: 1, padding: '32px 24px', overflowY: 'auto' }}>
          <Routes>
            <Route path="/" element={<DashboardHome />} />
            <Route path="/approvals" element={<ProviderApprovals />} />
            <Route path="/users" element={<UserManagement />} />
            <Route path="/bookings" element={<AllBookings />} />
          </Routes>
        </div>
      </div>
    </div>
  );
}
